using UnityEngine;\n\npublic class MobileInputManager : MonoBehaviour {\n    private Vector2 touchPosition;\n    private bool isTouching = false;\n\n    // Update is called once per frame\n    void Update() {\n        HandleTouchInput();\n    }\n\n    private void HandleTouchInput() {\n        if (Input.touchCount > 0) {\n            Touch touch = Input.GetTouch(0);\n\n            switch (touch.phase) {\n                case TouchPhase.Began:  // Touch started\n                    isTouching = true;\n                    touchPosition = touch.position;\n                    break;\n                case TouchPhase.Moved:  // Touch moving\n                    touchPosition = touch.position;\n                    break;\n                case TouchPhase.Ended:  // Touch ended\n                case TouchPhase.Canceled:  // Touch was cancelled\n                    isTouching = false;\n                    break;\n            }\n        }\n    }\n\n    public Vector2 GetTouchPosition() {\n        return isTouching ? touchPosition : Vector2.zero;\n    }\n\n    // Your joystick and button handling methods go here\n}\n